import { describe, expect, it } from 'vitest';

import { HostShim } from '../src/host-shim';
import { tensorNamesForLayer } from '../src/tensor-names';
import type { KnotByteSource } from '../src/types';
import {
  buildFakeKnot,
  buildMockWasmModule,
  expectedResidentNames,
  RecordingKnotSource,
} from './fixtures';

describe('HostShim.open', () => {
  it('parses the header, constructs backend + pipeline, and loads residents', async () => {
    const knot = buildFakeKnot({ numLayers: 2 });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
    });

    expect(shim.knotHeader().payloadOffset).toBe(knot.payloadOffset);
    expect(wasm.lastBackend).not.toBeNull();
    expect(wasm.lastPipeline).not.toBeNull();

    const expectedResidents = expectedResidentNames(true);
    expect(shim.residentTensorNames()).toEqual(expectedResidents);

    const setNames = wasm.lastBackend!.setCalls.map((c) => c.name);
    expect(setNames).toEqual(expectedResidents);
    // The first call (header probe) plus one rangeGet per resident tensor.
    expect(source.calls.length).toBe(1 + expectedResidents.length);
  });

  it('skips output_weight when metadata omits it (tied embeddings)', async () => {
    const knot = buildFakeKnot({ numLayers: 1, includeOutputWeight: false });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
    });

    expect(shim.residentTensorNames()).toEqual(
      expectedResidentNames(false),
    );
    const setNames = wasm.lastBackend!.setCalls.map((c) => c.name);
    expect(setNames).not.toContain('output_weight');
  });
});

describe('HostShim.prefetchLayer', () => {
  it('issues nine rangeGet calls and nine set_tensor calls per layer', async () => {
    const knot = buildFakeKnot({ numLayers: 4, layerTensorBytes: 32 });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
      lruCapacity: 4,
    });

    const setsBefore = wasm.lastBackend!.setCalls.length;
    const rangesBefore = source.calls.length;

    await shim.prefetchLayer(0);

    const newSets = wasm.lastBackend!.setCalls.slice(setsBefore);
    const newRanges = source.calls.slice(rangesBefore);

    expect(newSets).toHaveLength(9);
    expect(newRanges).toHaveLength(9);

    const expectedNames = tensorNamesForLayer(0);
    expect(newSets.map((c) => c.name).sort()).toEqual(expectedNames.slice().sort());

    // No eviction yet — first layer fits within capacity.
    expect(wasm.lastBackend!.evictCalls).toHaveLength(0);
    expect(shim.residentLayers()).toEqual([0]);
  });

  it('fetches the correct byte ranges (offset is payloadOffset + tensor.offset, length matches)', async () => {
    const knot = buildFakeKnot({ numLayers: 1, layerTensorBytes: 24 });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
    });

    source.reset();
    await shim.prefetchLayer(0);

    // Each call should target a tensor inside the payload region.
    for (const call of source.calls) {
      expect(call.start).toBeGreaterThanOrEqual(knot.payloadOffset);
      expect(call.length).toBe(24);
      expect(call.end - call.start + 1).toBe(24);
    }
  });

  it('throws when the requested layer is missing from the knot', async () => {
    const knot = buildFakeKnot({ numLayers: 1 });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();
    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
    });

    await expect(shim.prefetchLayer(99)).rejects.toThrow(/no tensor_info/);
  });
});

describe('HostShim LRU eviction', () => {
  it('evicts the oldest layer once capacity is exceeded', async () => {
    const knot = buildFakeKnot({ numLayers: 4 });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
      lruCapacity: 2,
    });

    await shim.prefetchLayer(0);
    await shim.prefetchLayer(1);
    expect(wasm.lastBackend!.evictCalls).toHaveLength(0);

    // This third prefetch should evict layer 0.
    await shim.prefetchLayer(2);
    expect(wasm.lastBackend!.evictCalls).toHaveLength(1);
    expect(wasm.lastBackend!.evictCalls[0]!.names).toEqual(tensorNamesForLayer(0));

    // Fourth should evict layer 1.
    await shim.prefetchLayer(3);
    expect(wasm.lastBackend!.evictCalls).toHaveLength(2);
    expect(wasm.lastBackend!.evictCalls[1]!.names).toEqual(tensorNamesForLayer(1));

    expect(shim.residentLayers()).toEqual([2, 3]);
  });

  it('does NOT evict resident tensors no matter how many layers churn through', async () => {
    const knot = buildFakeKnot({ numLayers: 5 });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
      lruCapacity: 1,
    });

    const residentsAtOpen = shim.residentTensorNames().slice();

    // Churn through all 5 layers — each new layer evicts the previous one.
    for (let l = 0; l < 5; l += 1) {
      // eslint-disable-next-line no-await-in-loop
      await shim.prefetchLayer(l);
    }

    // 4 evictions (layers 0..3) plus zero for the still-resident layer 4.
    expect(wasm.lastBackend!.evictCalls).toHaveLength(4);

    // No evict call ever names a resident tensor.
    const everEvicted = wasm.lastBackend!.evictCalls.flatMap((c) => c.names);
    for (const resident of residentsAtOpen) {
      expect(everEvicted).not.toContain(resident);
    }

    // And residents were each set exactly once (during open()).
    const setCountsByName = new Map<string, number>();
    for (const c of wasm.lastBackend!.setCalls) {
      setCountsByName.set(c.name, (setCountsByName.get(c.name) ?? 0) + 1);
    }
    for (const resident of residentsAtOpen) {
      expect(setCountsByName.get(resident)).toBe(1);
    }
  });

  it('re-touching a resident layer bumps it to MRU without eviction', async () => {
    const knot = buildFakeKnot({ numLayers: 3 });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
      lruCapacity: 2,
    });

    await shim.prefetchLayer(0);
    await shim.prefetchLayer(1);
    // Re-touch layer 0 — should not evict.
    await shim.prefetchLayer(0);
    expect(wasm.lastBackend!.evictCalls).toHaveLength(0);

    // Now touching layer 2 should evict layer 1 (the LRU after the bump).
    await shim.prefetchLayer(2);
    expect(wasm.lastBackend!.evictCalls).toHaveLength(1);
    expect(wasm.lastBackend!.evictCalls[0]!.names).toEqual(tensorNamesForLayer(1));
  });
});

describe('HostShim.generate', () => {
  it('preloads every layer then forwards prompt + max to the pipeline', async () => {
    const knot = buildFakeKnot({ numLayers: 3 });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
      lruCapacity: 3,
    });

    const prompt = new Uint32Array([1, 2, 3, 4]);
    const out = await shim.generate(prompt, 5);

    expect(out).toBeInstanceOf(Uint32Array);
    expect(out.length).toBe(5);
    expect(wasm.lastPipeline!.generateCalls).toHaveLength(1);
    expect(wasm.lastPipeline!.generateCalls[0]!.max).toBe(5);
    // Every layer should have been prefetched.
    expect(shim.residentLayers().sort()).toEqual([0, 1, 2]);
  });
});

describe('HostShim.fetchTensorBytes (partial-read safety)', () => {
  /**
   * Wraps a RecordingKnotSource and intercepts the FIRST tensor-payload range
   * fetch (i.e. anything past the header probe) with a configurable mutation:
   * short-read, exact-read, or over-read. The header-probe call (the very
   * first rangeGet) is always passed through untouched so HostShim.open can
   * parse the knot.
   */
  class TamperingSource implements KnotByteSource {
    public callCount = 0;
    constructor(
      private readonly inner: RecordingKnotSource,
      private readonly mutate: (bytes: Uint8Array) => Uint8Array,
    ) {}
    async rangeGet(start: number, end: number): Promise<Uint8Array> {
      const real = await this.inner.rangeGet(start, end);
      this.callCount += 1;
      // Pass the header probe through; only mutate subsequent (tensor) fetches.
      if (this.callCount === 1) return real;
      return this.mutate(real);
    }
  }

  it('throws on short read with a message that names the tensor and both byte counts', async () => {
    const knot = buildFakeKnot({ numLayers: 1, residentTensorBytes: 16 });
    const recording = new RecordingKnotSource(knot.bytes);
    // Drop the last 4 bytes of every tensor fetch.
    const source = new TamperingSource(recording, (b) => b.subarray(0, b.length - 4));
    const wasm = buildMockWasmModule();

    await expect(
      HostShim.open(source, wasm, { headerFetchBytes: knot.bytes.length }),
    ).rejects.toThrow(
      /fetchTensorBytes\(token_embd_weight\): source returned 12 bytes, expected 16\. Refusing to zero-pad/,
    );
  });

  it('returns bytes unchanged when the source returns exactly info.length', async () => {
    const knot = buildFakeKnot({ numLayers: 1, residentTensorBytes: 16, layerTensorBytes: 16 });
    const recording = new RecordingKnotSource(knot.bytes);
    // Identity mutation — pass bytes through untouched.
    const source = new TamperingSource(recording, (b) => b);
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
    });
    await shim.prefetchLayer(0);

    // Every recorded set_tensor must carry exactly info.length bytes, and
    // those bytes must match the deterministic fixture content (no padding,
    // no truncation).
    const backend = wasm.lastBackend!;
    const tensors = knot.metadata.tensors;
    for (const call of backend.setCalls) {
      const info = tensors[call.name];
      expect(info).toBeDefined();
      expect(call.bytes.length).toBe(info!.length);
      // Spot-check first and last byte against the fixture's deterministic fill.
      const expectedStart = knot.payloadOffset + info!.offset;
      expect(call.bytes[0]).toBe(knot.bytes[expectedStart]);
      expect(call.bytes[info!.length - 1]).toBe(
        knot.bytes[expectedStart + info!.length - 1],
      );
    }
  });

  it('trims to info.length when the source over-reads (returns more than requested)', async () => {
    const knot = buildFakeKnot({ numLayers: 1, residentTensorBytes: 16, layerTensorBytes: 16 });
    const recording = new RecordingKnotSource(knot.bytes);
    // Append 8 trailing sentinel bytes to every tensor fetch.
    const SENTINEL = 0xab;
    const source = new TamperingSource(recording, (b) => {
      const out = new Uint8Array(b.length + 8);
      out.set(b, 0);
      for (let i = b.length; i < out.length; i += 1) out[i] = SENTINEL;
      return out;
    });
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
    });
    await shim.prefetchLayer(0);

    const backend = wasm.lastBackend!;
    const tensors = knot.metadata.tensors;
    expect(backend.setCalls.length).toBeGreaterThan(0);
    for (const call of backend.setCalls) {
      const info = tensors[call.name];
      expect(info).toBeDefined();
      // Trimmed exactly to info.length — no sentinel bytes leak through.
      expect(call.bytes.length).toBe(info!.length);
      expect(Array.from(call.bytes)).not.toContain(SENTINEL);
    }
  });

  it('retries once after a transient tensor range failure', async () => {
    const knot = buildFakeKnot({ numLayers: 1, residentTensorBytes: 16, layerTensorBytes: 16 });
    const recording = new RecordingKnotSource(knot.bytes);
    let tensorFetchAttempts = 0;
    const source: KnotByteSource = {
      async rangeGet(start: number, end: number): Promise<Uint8Array> {
        const real = await recording.rangeGet(start, end);
        tensorFetchAttempts += 1;
        if (tensorFetchAttempts === 2) {
          throw new Error('transient upstream 502');
        }
        return real;
      },
    };
    const wasm = buildMockWasmModule();

    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
    });
    await shim.prefetchLayer(0);

    expect(tensorFetchAttempts).toBeGreaterThanOrEqual(3);
    const backend = wasm.lastBackend!;
    expect(backend.setCalls.length).toBeGreaterThan(0);
  });
});

describe('HostShim.dispose', () => {
  it('frees backend + pipeline and rejects subsequent calls', async () => {
    const knot = buildFakeKnot({ numLayers: 1 });
    const source = new RecordingKnotSource(knot.bytes);
    const wasm = buildMockWasmModule();
    const shim = await HostShim.open(source, wasm, {
      headerFetchBytes: knot.bytes.length,
    });

    shim.dispose();
    expect(wasm.lastBackend!.freed).toBe(true);
    expect(wasm.lastPipeline!.freed).toBe(true);

    await expect(shim.prefetchLayer(0)).rejects.toThrow(/disposed/);
    expect(() => shim.getPos()).toThrow(/disposed/);

    // Idempotent.
    expect(() => shim.dispose()).not.toThrow();
  });
});
